dark.customCSS:
/* --- BIO-DIGITAL SYNTHESIS: LIVING UI --- */

@keyframes bio-pulse {
  0% { border-color: rgba(207, 51, 255, 0.2); }
  50% { border-color: rgba(0, 255, 234, 0.4); }
  100% { border-color: rgba(207, 51, 255, 0.2); }
}

/* The Living Panel */
.markdown-prose, .bg-gray-850, input, textarea, #chat-input-container {
	background: rgba(12, 0, 16, 0.6) !important;
	backdrop-filter: blur(12px) !important;
	-webkit-backdrop-filter: blur(12px) !important;
	border: 1px solid rgba(207, 51, 255, 0.3) !important;
	border-radius: 20px !important;
	animation: bio-pulse 4s infinite ease-in-out;
}

/* Spinal Scrollbar */
::-webkit-scrollbar {
	width: 10px;
}
::-webkit-scrollbar-thumb {
	background: linear-gradient(#cf33ff, #00ffea) !important;
	border: 3px solid #06000a;
	border-radius: 20px;
}
::-webkit-scrollbar-track {
	background: #06000a !important;
}

/* Synapse Headers */
.markdown-prose h1, .markdown-prose h2, .markdown-prose h3 {
	color: #00ffea !important;
	text-shadow: 0 0 10px rgba(0, 255, 234, 0.3);
	font-weight: 200 !important;
	letter-spacing: 0.05em;
}

/* Biomech Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: transparent !important;
	color: #00ffea !important;
	border: 1px solid #00ffea !important;
	text-transform: uppercase;
	font-weight: 800 !important;
	letter-spacing: 2px;
	border-radius: 4px !important;
	box-shadow: inset 0 0 10px rgba(0, 255, 234, 0.2);
	transition: all 0.2s ease;
}

button.bg-blue-500:hover {
	background: #00ffea !important;
	color: #06000a !important;
	box-shadow: 0 0 30px rgba(0, 255, 234, 0.6) !important;
}

/* Hide structural noise */
#sidebar {
	background: rgba(6, 0, 10, 0.85) !important;
	border-right: 1px solid rgba(207, 51, 255, 0.2) !important;
}

dark.canvasScript:
/**
 * Title: Synaptic Network
 * Description: Neural nodes that fire and connect when stimulated by the mouse.
 */

const CONFIG = {
    nodeCount: 100,
    connectDist: 150,
    nodeColor: 'rgba(207, 51, 255, 0.5)',
    synapseColor: 'rgba(0, 255, 234, 0.2)',
    stimulusColor: 'rgba(0, 255, 234, 0.8)',
    stimulusRadius: 200
};

let canvas, ctx, w, h;
let nodes = [];
let mouse = { x: -5000, y: -5000 };

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    nodes = [];
    for (let i = 0; i < CONFIG.nodeCount; i++) {
        nodes.push({ 
            x: Math.random() * w, y: Math.random() * h, 
            vx: (Math.random() - 0.5) * 0.8, vy: (Math.random() - 0.5) * 0.8, 
            stim: 0 
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    for (let i = 0; i < nodes.length; i++) {
        let n = nodes[i];
        n.x += n.vx; n.y += n.vy;
        if (n.x < 0 || n.x > w) n.vx *= -1; if (n.y < 0 || n.y > h) n.vy *= -1;

        let dxMouse = mouse.x - n.x; let dyMouse = mouse.y - n.y;
        let dMouse = Math.hypot(dxMouse, dyMouse);
        n.stim = dMouse < CONFIG.stimulusRadius ? (1 - dMouse / CONFIG.stimulusRadius) : 0;

        for (let j = i + 1; j < nodes.length; j++) {
            let n2 = nodes[j];
            let dist = Math.hypot(n2.x - n.x, n2.y - n.y);
            if (dist < CONFIG.connectDist) {
                ctx.beginPath();
                ctx.moveTo(n.x, n.y); ctx.lineTo(n2.x, n2.y);
                let alpha = (1 - dist / CONFIG.connectDist) * 0.2;
                ctx.strokeStyle = n.stim > 0.5 ? `rgba(0, 255, 234, ${alpha * 2})` : CONFIG.synapseColor;
                ctx.lineWidth = n.stim > 0.5 ? 1.5 : 0.5;
                ctx.stroke();
            }
        }

        ctx.beginPath();
        ctx.arc(n.x, n.y, 2 + n.stim * 3, 0, Math.PI * 2);
        ctx.fillStyle = n.stim > 0.5 ? CONFIG.stimulusColor : CONFIG.nodeColor;
        ctx.fill();
    }
    requestAnimationFrame(render);
}

